import{_ as r}from"./plugin-vue_export-helper-x3n3nnut.js";import{r as s,o as t,c as o,b as e,d as n,e as l,w as c,a as i}from"./app-ZyFXnamq.js";const d="/assets/images/2023/20231213.电力分类_En.jpg",g="/assets/images/2023/20231213.新型电力系统_En.jpg",h="/assets/images/2023/20231213.2018年我国二氧化碳排放按行业细分_En.jpg",u="/assets/images/2023/20231213.主要行业成本构成_En.jpg",m="/assets/images/2023/20231213.各行业脱碳路径_En.png",p="/assets/images/2023/20231213.绿色金融产业碳中和关系_En.jpg",f={},y=e("p",null,"This article is a reading note of Ernst & Young's 'Understanding Carbon Neutrality Through a Book', divided into two parts. This piece covers the second part.",-1),b=i('<h2 id="_17-challenges-and-strategies-of-carbon-neutrality-in-the-power-industry" tabindex="-1"><a class="header-anchor" href="#_17-challenges-and-strategies-of-carbon-neutrality-in-the-power-industry" aria-hidden="true">#</a> 17. Challenges and Strategies of Carbon Neutrality in the Power Industry</h2><figure><img src="'+d+'" alt="Power Categorization" tabindex="0" loading="lazy"><figcaption>Power Categorization</figcaption></figure><ol><li><strong>Dependence on Fossil Fuels</strong>: Power still heavily relies on coal, natural gas, and other fossil fuels, which are major sources of carbon emissions.</li><li><strong>Intermittency and Instability of Renewable Energy</strong>: Solar and wind energy, being renewable sources, are greatly affected by weather and seasons, making it difficult to provide stable power supply.</li><li><strong>Infrastructure and Technological Limitations</strong>: Existing grids and facilities might not fully adapt to the large-scale integration of renewable energy and distributed generation.</li><li><strong>Economic Costs</strong>: Transitioning to a low-carbon or carbon-free energy system may require substantial investment, especially in developing and upgrading infrastructure.</li><li><strong>Policy and Market Mechanisms</strong>: Lack of effective policy support and market mechanisms may hinder the development and application of low-carbon technologies.</li><li><strong>Increasing Renewable Energy Proportion</strong>: Vigorously developing clean energy such as solar, wind, and hydro power to gradually replace fossil fuel power generation. By 2050, renewable energy installations in China will account for 92%, with photovoltaic and wind power installations exceeding 75%, and coal power installations at 4%. By 2060, the proportion of renewable energy installations will rise to 96%, with photovoltaic and wind power installations reaching nearly 80%, and coal power installations for peak shaving will be phased out.</li><li><strong>Grid Upgrading and Smartization</strong>: Improve grid infrastructure to enhance its capacity for renewable energy integration and develop smart grid technology to optimize power distribution and usage.</li><li><strong>Development of Energy Storage Technology</strong>: Invest in advanced storage technologies (such as battery storage, pumped hydro storage) to balance the intermittency and instability of renewable sources.</li><li><strong>Carbon Capture and Storage Technology (CCS/CCUS)</strong>: For power plants still needing fossil fuels, adopt CCS or CCUS technology to reduce carbon emissions.</li><li><strong>Promoting Green Finance and Investment</strong>: Encourage and guide capital towards low-carbon and renewable energy projects, supporting industry transformation through green bonds and green funds.</li><li><strong>Formulating Supportive Policies</strong>: Establish policies favorable to the development of renewable energy, including subsidies, tax incentives, and renewable energy quota systems.</li><li><strong>International Cooperation and Technological Exchange</strong>: Strengthen international cooperation, share low-carbon technologies, and jointly address climate change challenges.</li></ol><h2 id="_18-advantages-and-challenges-of-photovoltaic-power-generation" tabindex="-1"><a class="header-anchor" href="#_18-advantages-and-challenges-of-photovoltaic-power-generation" aria-hidden="true">#</a> 18. Advantages and Challenges of Photovoltaic Power Generation</h2><ol><li><strong>Advantages: Rich Natural Resources</strong>: China has abundant solar energy resources, especially in the northwestern region.</li><li><strong>Advantages: Strong Industrial Capacity</strong>: In terms of industrial capacity and technological costs, China has a solid development foundation.</li><li><strong>Advantages: Gradually Decreasing Costs</strong>: In recent years, the cost of photovoltaic power generation has been continuously declining, becoming competitive with thermal power.</li><li><strong>Disadvantages: Land Constraints</strong>: Development of photovoltaic power is closely related to national spatial planning, facing restrictions on land use.</li><li><strong>Disadvantages: High Non-technical Costs</strong>: Due to taxes and other non-technical costs, the total cost of photovoltaic power projects remains high.</li><li><strong>Challenges: Grid Integration and Consumption</strong>: As the scale of photovoltaic power generation expands, how to effectively consume photovoltaic electricity becomes a major challenge.</li><li><strong>Challenges: Abandoned Power Issue</strong>: In some areas, especially in the northwest, the abandonment rate of photovoltaic power is high and needs to be further reduced.</li><li><strong>Challenges: Policy and Market Mechanisms</strong>: Need to improve grid integration and consumption guarantee mechanisms for photovoltaic power, as well as market-based trading policies.</li><li><strong>Challenges: Technological R&amp;D</strong>: Support the development of efficient batteries and component products, increase the application of advanced battery technologies, and solve grid integration technology issues.</li></ol><p>To address these challenges, it is recommended to accelerate the construction of centralized and distributed photovoltaic power generation, improve electricity output capacity through large grids and ultra-high-voltage transmission lines, increase &quot;photovoltaic power generation + energy storage&quot; configurations, and strengthen policy coordination and technological innovation.</p><h2 id="_19-advantages-disadvantages-and-challenges-of-wind-energy" tabindex="-1"><a class="header-anchor" href="#_19-advantages-disadvantages-and-challenges-of-wind-energy" aria-hidden="true">#</a> 19. Advantages, Disadvantages, and Challenges of Wind Energy</h2><ol><li>Advantage: <strong>Abundant Resources</strong>: Especially in the &quot;Three Norths&quot; and coastal areas, China has rich wind energy resources.</li><li>Advantage: <strong>Technological Progress</strong>: Wind energy technology is continuously advancing, with gradually decreasing costs, especially in offshore wind power.</li><li>Disadvantage: <strong>Geographical Limitations</strong>: Wind energy projects need to be concentrated in areas with abundant wind resources, which are often remotely located.</li><li>Disadvantage: <strong>Environmental Impact</strong>: Wind power development must comply with ecological environmental standards, avoiding industrial and rural infrastructure, and also meet noise standards.</li><li>Challenge: <strong>Grid Integration and Consumption Issues</strong>: Large-scale wind power development faces challenges in transmission and grid integration, leading to &quot;wind curtailment&quot; phenomena.</li><li>Challenge: <strong>High Investment and O&amp;M Requirements</strong>: Centralized wind turbine units require significant investment and high operational and maintenance technical standards.</li><li>Challenge: <strong>Economic Efficiency of Scale Issues</strong>: Distributed wind turbine units have limited economies of scale, with small businesses facing financing difficulties and large enterprises showing weak investment intentions.</li><li>Challenge: <strong>Changes in National Subsidy Policies</strong>: Onshore wind power projects are shifting to grid parity, and subsidies for offshore wind projects are being phased out, increasing cost pressures.</li><li>Challenge: <strong>Need for Further Improvement in Technology and Market Mechanisms</strong>: Further enhancements in wind power technology and cost reduction are needed, along with strengthening the construction of power markets and consumption mechanisms.</li></ol><h2 id="_20-advantages-disadvantages-and-challenges-of-hydropower" tabindex="-1"><a class="header-anchor" href="#_20-advantages-disadvantages-and-challenges-of-hydropower" aria-hidden="true">#</a> 20. Advantages, Disadvantages, and Challenges of Hydropower</h2><ol><li><strong>Advantage</strong>: China has started hydropower development early, achieving high technical maturity, energy density, and economic benefits, without the intermittency issues of solar and wind power.</li><li><strong>Geographical Location and Development Difficulty</strong>: China&#39;s undeveloped hydropower resources are mostly concentrated in the upper reaches of rivers and remote areas like Tibet, where challenging environmental conditions increase the difficulty and cost of hydropower construction.</li><li><strong>Constraints of Ecological Protection</strong>: Hydropower projects can have irreversible impacts on the surrounding environmental ecology. For example, dam construction may increase the risks of earthquakes and landslides, alter aquatic ecosystems, threaten fisheries, and cause downstream dry-up.</li><li><strong>Water Quality Issues</strong>: Long-term water storage can weaken the self-purification capacity of water bodies, leading to water quality degradation in some areas and downstream, severely damaging the ecological environment.</li><li><strong>Issues with Resettlement of People</strong>: The construction of hydropower projects often requires resettlement of people, a process that is becoming increasingly challenging.</li></ol><h2 id="_21-how-to-transform-the-power-grid-to-reduce-dependence-on-traditional-thermal-power" tabindex="-1"><a class="header-anchor" href="#_21-how-to-transform-the-power-grid-to-reduce-dependence-on-traditional-thermal-power" aria-hidden="true">#</a> 21. How to Transform the Power Grid to Reduce Dependence on Traditional Thermal Power?</h2><figure><img src="'+g+'" alt="New Type of Power System" tabindex="0" loading="lazy"><figcaption>New Type of Power System</figcaption></figure><ol><li><strong>Multi-Energy Complementary Power Generation</strong>: Combining wind, solar, hydro, thermal, and storage to form a new type of power system, enhancing supply reliability.</li><li><strong>Regional Development Strategy</strong>: According to resource distribution, large-scale wind and photovoltaic bases in the northwest, offshore wind power along the southeast coast, and distributed photovoltaics in the eastern and central regions.</li><li><strong>Ultra-High Voltage Main Grid</strong>: Long-distance power transmission to optimize national energy allocation and solve the &quot;west-to-east power transmission&quot; issue.</li><li><strong>Microgrid Construction</strong>: Independent small-scale grid systems to improve power supply stability in remote areas and industrial parks.</li><li><strong>Smart Grid Upgrades</strong>: Utilizing new technologies to enhance grid control level for efficient power management.</li><li><strong>Next-Generation Control Systems</strong>: Relying on high-tech to comprehensively cover all aspects of the power system, improving precision and safety in control.</li><li><strong>Electricity Demand Response Mechanism</strong>: Regulating power consumption through pricing or incentive strategies to optimize resource allocation.</li><li><strong>Construction of the Electric Power Market System</strong>: Establishing multi-level electricity trading platforms, advancing marketization of electricity, and ensuring priority grid connection for new energy sources.</li><li><strong>Diverse Energy Storage Technologies</strong>: Including mechanical, electromagnetic, electrochemical, and hydrogen storage, each with unique characteristics suitable for different scenarios. <ul><li><strong>Mechanical Storage Types</strong>: Including pumped hydro storage, flywheels, and compressed air energy storage, known for strong peak regulation capacity and relatively mature technology.</li><li><strong>Advantages of Electrochemical Storage</strong>: Rapid response, flexible adaptation to various environments, but with issues in lifespan and cost.</li><li><strong>Potential of Hydrogen Storage</strong>: An ideal long-term storage method, facing challenges in hydrogen production efficiency and storage and transportation technology.</li></ul></li><li><strong>Application Scenarios of Energy Storage Technology</strong>: Distributed across the supply side, grid side, and user side, enhancing the performance of the power system.</li></ol><h2 id="_22-what-is-non-electric-carbon-neutrality" tabindex="-1"><a class="header-anchor" href="#_22-what-is-non-electric-carbon-neutrality" aria-hidden="true">#</a> 22. What is Non-Electric Carbon Neutrality?</h2><ul><li><p>Non-electric carbon neutrality refers to achieving carbon emission reduction or neutralization in non-electric sectors. This involves industries such as industrial manufacturing, transportation, construction, and agriculture, which operate outside the electricity sector.</p><figure><img src="'+h+'" alt="2018 China&#39;s CO2 Emissions by Industry Segmentation" tabindex="0" loading="lazy"><figcaption>2018 China&#39;s CO2 Emissions by Industry Segmentation</figcaption></figure><figure><img src="'+u+'" alt="Main Industry Cost Composition" tabindex="0" loading="lazy"><figcaption>Main Industry Cost Composition</figcaption></figure></li></ul><h2 id="_23-how-to-achieve-carbon-neutrality-in-the-steel-industry" tabindex="-1"><a class="header-anchor" href="#_23-how-to-achieve-carbon-neutrality-in-the-steel-industry" aria-hidden="true">#</a> 23. How to Achieve Carbon Neutrality in the Steel Industry?</h2><ol><li><strong>Importance of the Steel Industry</strong>: Steel is fundamental to industrial development, supporting China&#39;s infrastructure construction and industrialization.</li><li><strong>High Carbon Emission Industry</strong>: The steel industry is a high energy consumption and high pollution sector, with China&#39;s steel industry carbon emissions accounting for more than half of the global total.</li><li><strong>Production Process Characteristics</strong>: Steel production includes long processes (mainly coal-based) and short processes (mainly scrap-based), with blast furnace smelting being the main carbon-emitting step.</li><li><strong>Emission Reduction Pressure and Targets</strong>: Facing significant carbon emission reduction pressure, the goal is to peak carbon emissions by 2025 and reduce them by 30% from the peak by 2030.</li><li><strong>Trends in Consumption Demand</strong>: With urbanization, the demand for steel is expected to gradually decrease.</li><li><strong>Industry Consolidation and Restructuring</strong>: Consolidation to improve market competitiveness and optimize industrial structure is a key path to achieving carbon neutrality.</li><li><strong>Development of Green and Low-Carbon Technologies</strong>: Promote electric arc furnace steelmaking, hydrogen metallurgy, CCUS technology, etc., to reduce carbon emissions.</li><li><strong>Policy and Technological Innovation</strong>: Government policies are needed to promote technological innovation and improve market mechanisms.</li><li><strong>Challenges in Electric Arc Furnace Steelmaking</strong>: Facing cost and environmental issues, it is necessary to optimize production processes and improve efficiency.</li><li><strong>Application of Hydrogen and CCUS Technology</strong>: Hydrogen as a clean energy source is in the early stages of application in the steel industry, while CCUS technology is expected to be promoted in steel plants.</li></ol><h2 id="_24-how-to-achieve-carbon-neutrality-in-the-cement-industry" tabindex="-1"><a class="header-anchor" href="#_24-how-to-achieve-carbon-neutrality-in-the-cement-industry" aria-hidden="true">#</a> 24. How to Achieve Carbon Neutrality in the Cement Industry?</h2><ol><li><strong>Importance of the Cement Industry</strong>: Cement is the most widely used building material globally, vital for urbanization and infrastructure but also a major source of CO2 emissions.</li><li><strong>Status of China&#39;s Cement Industry</strong>: Accounting for 7% of global carbon emissions, China is a major cement producer, historically significant for economic construction. Despite slower growth in production, China remains the world&#39;s largest cement supplier.</li><li><strong>Cement Industry Chain</strong>: Includes upstream raw material mining, midstream production manufacturing (two grinding and one burning process), and downstream infrastructure application. Limestone, a major raw material, releases large amounts of CO2 during decomposition and combustion.</li><li><strong>Sources of Cement Carbon Emissions</strong>: About 50% from limestone chemical reactions, 40% from burning fossil fuels for calcination, and 10% from electricity consumption and raw material transportation.</li><li><strong>Cement Industry&#39;s “Zero Carbon” Goal</strong>: Planned decarbonization by 2060 with comprehensive technological upgrades. The China Building Materials Federation has proposed technological development goals, including new low-carbon cement production technologies and carbon capture technologies.</li><li><strong>Future Transformations in the Cement Industry</strong>: Carbon capture technology is expected to reach commercial scale by 2030, with increased demand for clinker substitutes by 2050. China&#39;s cement industry demand is anticipated to gradually decline.</li><li><strong>Improving Energy Efficiency</strong>: Reduce heat loss through technological optimization and process improvement, increase kiln thermal efficiency, and apply waste heat power generation to improve power efficiency.</li><li><strong>Adoption of Alternative Fuels</strong>: Cement kiln co-processing technology uses waste as an alternative fuel, reducing energy consumption and environmental pollution, such as disposing of medical waste during the pandemic.</li><li><strong>Promotion of Biomass Fuel Replacement Technology</strong>: Biomass fuels as an alternative energy source used at the front end of cement kilns play a significant role in reducing reliance on fossil fuels and lowering carbon emissions.</li><li><strong>Using Industrial Waste as Alternative Raw Materials</strong>: Utilizing industrial waste, such as paper mill sludge and calcium carbide slag, as cement raw materials can effectively reduce CO2 emissions, especially with high potential in North and Southwest China.</li><li><strong>Application of Carbon Capture Technology (CCUS)</strong>: Post-combustion CO2 capture technology in the cement industry addresses carbon emission challenges while balancing technological and economic efficiency.</li><li><strong>Development of New Green Cements</strong>: New types of cement, such as magnesium silicate cement, can absorb CO2 during the hardening process, achieving negative carbon emissions and helping the cement industry transition from a carbon emitter to a carbon absorber.</li></ol><h2 id="_25-how-to-achieve-carbon-neutrality-in-the-chemical-industry" tabindex="-1"><a class="header-anchor" href="#_25-how-to-achieve-carbon-neutrality-in-the-chemical-industry" aria-hidden="true">#</a> 25. How to Achieve Carbon Neutrality in the Chemical Industry?</h2><ol><li><strong>Role of the Chemical Industry</strong>: China&#39;s chemical industry is a crucial pillar of the national economy, providing essential goods. Although its carbon emissions are lower than those of the steel and cement industries, the pathways are complex.</li><li><strong>Carbon Emissions in the Chemical Industry</strong>: Although the chemical industry itself accounts for less than 5% of China&#39;s total emissions (as of 2018), it is one of the high energy-consuming industries, making the path to carbon reduction complex yet crucial.</li><li><strong>Chemical Industry Chain</strong>: It involves processes from crude oil and coal mining to chemical product production, with products widely used in daily life and upstream industries having high carbon emissions.</li><li><strong>Carbon Emission Challenges</strong>: The chemical industry needs to balance carbon neutrality goals with national economic growth. Although the emissions are relatively small, the absolute value remains significant.</li><li><strong>Basic Chemical Industry</strong>: Based on coal and oil, it produces plastics, synthetic fibers, synthetic rubber, etc., with relatively low technical barriers.</li><li><strong>Carbon Sources in the Chemical Industry</strong>: Mainly from coal and oil, transformed into final products through combustion and chemical processes, with different products having varying carbon requirements.</li><li><strong>Carbon Emission Accounting</strong>: Uses accounting methods that include fuel combustion, waste gas combustion, and various aspects of industrial production processes.</li><li><strong>Zero-Carbon Future of the Chemical Industry</strong>: By 2060, the scale of coal chemical production may shrink, adopting CCUS and Power-to-X technologies, as well as replacing with bio-based polymers.</li><li><strong>Supply-Side Reforms</strong>: Carbon neutrality promotes high-quality reform in the chemical industry, where leading enterprises will have more competitive advantages, while smaller companies may face elimination.</li><li><strong>Whole Industry Chain Carbon Reduction</strong>: From raw materials, processes to product end, adopting clean energy, bio-based materials, etc., to achieve carbon reduction and a circular economy.</li></ol><h2 id="_26-how-to-achieve-carbon-neutrality-in-the-transportation-industry" tabindex="-1"><a class="header-anchor" href="#_26-how-to-achieve-carbon-neutrality-in-the-transportation-industry" aria-hidden="true">#</a> 26. How to Achieve Carbon Neutrality in the Transportation Industry?</h2><ol><li><strong>Current Status and Carbon Emissions of the Transportation Industry</strong>: Carbon emissions from China&#39;s transportation industry account for 10% of the total industry emissions, growing rapidly in recent years, mainly due to accelerated urbanization. The government is gradually reducing emissions through the development of public transportation and support for electrification of ground transportation, but emissions increase due to economic expansion remains a challenge.</li><li><strong>Zero-Carbon Goal by 2060</strong>: By 2060, the transportation industry is expected to achieve complete electrification, including private cars, buses, and high-speed trains, to meet carbon neutrality goals. Meanwhile, new technologies like cloud computing, big data, and artificial intelligence will drive the development of smart transportation, improving efficiency and reducing emissions.</li><li><strong>Development of New Energy Vehicles</strong>: New energy vehicles, including pure electric and hybrid vehicles, are key to decarbonizing the transportation industry. Hydrogen-fueled vehicles are also seen as an effective decarbonization tool. New energy vehicles have advantages like low energy consumption and high conversion rates and are supported by government policies.</li><li><strong>Challenges in Charging Infrastructure Construction</strong>: With the popularity of new energy vehicles, building enough charging stations has become a challenge. The development of charging stations needs to integrate manufacturing, operation, and platform stages to improve profitability and resource efficiency.</li><li><strong>Electrification of Trucks and Buses</strong>: Electrification of heavy trucks and buses is crucial for reducing exhaust emissions. Electric trucks can reduce operating costs and maintenance expenses, signaling a significant transformation in the transportation industry.</li><li><strong>Challenges in Battery Technology</strong>: Batteries are the core of new energy vehicles, and their range and safety are key to widespread adoption. Currently, battery technology faces challenges such as short range, slow charging, and safety issues. Solving these problems will be key to achieving decarbonization goals.</li><li><strong>Necessity of Smart Transportation</strong>: Large cities like Beijing face severe traffic congestion during peak hours, leading to high carbon emissions. The development of smart transportation is key to solving this problem and reducing carbon emissions, requiring the integration of advanced information technology and transportation.</li><li><strong>Government Support and Strategies</strong>: The Chinese government supports the development of smart transportation, releasing industry policies such as incorporating vehicle networking into new information infrastructure construction, promoting the rapid development of 5G, and building national-level vehicle networking pilot zones.</li><li><strong>Application of C-V2X Technology</strong>: Cellular Vehicle-to-Everything (C-V2X) technology includes vehicle-to-vehicle, vehicle-to-infrastructure, and vehicle-to-pedestrian connectivity, using roadside perception for information exchange and control, providing intelligent services like collision reports and autonomous driving.</li><li><strong>Infrastructure Investment and Challenges</strong>: China is increasing investment in infrastructure such as video detection radars, but technology applications face challenges in no-network environments or frequent scene switching.</li><li><strong>Role of 5G and Cloud Computing in Smart Transportation</strong>: The low latency and high reliability of 5G are crucial for vehicle networking, while cloud computing supports traffic data processing and optimization.</li><li><strong>Promotion of Shared Mobility</strong>: Shared mobility, like shared bicycles and cars, solves the &quot;last mile&quot; problem of public transportation, helping to reduce road traffic pressure and carbon emissions. Future autonomous driving technology will further promote the development of shared mobility services.</li></ol><h2 id="_27-how-to-achieve-carbon-neutrality-in-the-construction-industry" tabindex="-1"><a class="header-anchor" href="#_27-how-to-achieve-carbon-neutrality-in-the-construction-industry" aria-hidden="true">#</a> 27. How to Achieve Carbon Neutrality in the Construction Industry?</h2><ol><li><strong>Current Status and Urbanization in the Construction Industry</strong>: With accelerated urbanization, building area is rapidly increasing, leading to huge energy consumption. By 2050, building demand will significantly increase, making the construction industry a major energy consumer.</li><li><strong>Carbon Emission Sources in the Construction Industry</strong>: Carbon emissions in the construction industry mainly come from the production and transportation of building materials, construction, and building operations. The production of building materials, especially cement, generates a large amount of CO2.</li><li><strong>Energy Consumption and Carbon Emissions in Building Operations</strong>: During the building operation phase, especially for heating, cooling, and lighting, the construction industry consumes significant energy and emits substantial carbon. The reliance on coal and traditional electricity leads to high carbon emissions.</li><li><strong>Decarbonization Outlook for the Construction Industry by 2060</strong>: By 2060, the construction industry is expected to achieve carbon neutrality. This includes adopting new heating structures, electrification reforms, and optimizing construction and operation processes.</li><li><strong>Green Buildings and Low-Carbon Technologies</strong>: Future building designs will focus on green buildings, energy-saving appliances, and ecological technologies to achieve carbon neutrality, while improving the quality of life and comfort.</li><li><strong>Electrification of Building Energy Use</strong>: Comprehensive electrification, such as using electric heat pumps and intelligent variable frequency electrical stoves, can significantly reduce direct carbon emissions in the construction industry. Despite facing challenges in technological innovation, this transformation is crucial for reducing carbon emissions.</li><li><strong>Exploring New Heating Methods</strong>: Through centralized heating and environmentally friendly heating methods, like electric fans and electric heating films, higher energy efficiency and reduced carbon emissions can be achieved. These methods can improve heating efficiency while reducing environmental pollution.</li><li><strong>Localized Approaches to Reduce Energy Consumption</strong>: Utilizing local resources and traditional knowledge to reduce building energy consumption. Emphasizing the importance of local design and criticizing some modern buildings for energy wastage due to ignoring local conditions.</li><li><strong>Use of Energy-Saving Appliances and Eco-Friendly Materials</strong>: By adopting LED lighting, smart heating systems, and new energy-saving materials, indoor electricity consumption is significantly reduced, helping to lower overall energy consumption and carbon emissions.</li><li><strong>Development of Green Energy-Efficient Buildings</strong>: Through vertical greening and low-energy building design, such as rational planning of building orientation and spacing, effectively reducing energy consumption and urban heat island effect, while promoting CO2 absorption.</li></ol><h2 id="_28-how-to-achieve-carbon-neutrality-in-the-service-industry" tabindex="-1"><a class="header-anchor" href="#_28-how-to-achieve-carbon-neutrality-in-the-service-industry" aria-hidden="true">#</a> 28. How to Achieve Carbon Neutrality in the Service Industry?</h2><ol><li><strong>Current Status and Outlook of the Service Industry</strong>: The service industry includes courier logistics, residential services, retail, etc. Its energy consumption and carbon emissions increase with the industry&#39;s expansion, making energy saving and emission reduction important tasks.</li><li><strong>Greening of Courier Transportation</strong>: The courier industry reduces carbon emissions by using eco-friendly packaging, optimizing warehousing, and promoting new energy transportation tools, such as new energy vehicles.</li><li><strong>Low Carbon in the ICT Industry</strong>: The ICT industry reduces energy consumption and carbon emissions through optimizing data centers, lowering base station energy consumption, and improving equipment efficiency.</li><li><strong>Low-Carbon Retail Models</strong>: The retail industry achieves low-carbon development by reducing excessive packaging of goods, improving energy efficiency, and adopting environmentally friendly technologies.</li><li><strong>Low-Carbon Office Advocacy</strong>: Offices achieve low carbonization by reducing paper printing, optimizing business travel, and promoting resource recycling.</li><li><strong>Promoting Low-Carbon Lifestyle in Residential Services</strong>: The residential service industry promotes low-carbon living by advocating green consumption habits and environmental awareness, such as the sharing economy and eco-friendly financial products (e.g., Ant Forest).</li><li><strong>Green Transformation in E-commerce Logistics</strong>: E-commerce logistics companies reduce environmental impact by investing in new energy vehicles and promoting green packaging.</li><li><strong>Learning from Mature Low-Carbon Retail Models</strong>: Through inter-company exchanges and learning from successful international cases, local retail enterprises can effectively implement low-carbon strategies.</li></ol><h2 id="_29-what-are-negative-emission-technologies" tabindex="-1"><a class="header-anchor" href="#_29-what-are-negative-emission-technologies" aria-hidden="true">#</a> 29. What are Negative Emission Technologies?</h2><ol><li><strong>Concept and Role of Carbon Sinks</strong>: Utilizing the natural carbon cycle of ecosystems, such as vegetation, soil, and microorganisms, to sequester carbon dioxide, thereby reducing atmospheric CO2 concentrations.</li><li><strong>International Certification of Forestry Carbon Sinks</strong>: Forests store CO2 from the atmosphere through photosynthesis, forming carbon sinks, widely recognized by the international community as important measures to mitigate climate change. China&#39;s terrestrial ecosystems, especially the carbon storage function of forests, contribute significantly to global climate change mitigation.</li><li><strong>Importance of Oceanic Carbon Sinks</strong>: The ocean, as the largest active carbon reservoir on Earth, has the potential to store large amounts of carbon long-term and is an important source of carbon sinks.</li><li><strong>CCUS Technology</strong>: Carbon Capture, Utilization, and Storage (CCUS) involves capturing CO2 emitted from industrial processes and recycling it. CCUS not only reduces carbon emissions but also transforms captured CO2 into valuable products, having commercial potential. However, high costs and complex technological requirements limit its wide application.</li><li><strong>Direct Air Carbon Capture Technology</strong>: (Direct Air Capture, DAC) captures CO2 directly from the air, characterized by high flexibility and wide applicability, but faces challenges such as high costs.</li></ol><p>Summary Image:</p><figure><img src="'+m+'" alt="Decarbonization Pathways Across Industries" tabindex="0" loading="lazy"><figcaption>Decarbonization Pathways Across Industries</figcaption></figure><h2 id="_30-why-achieve-dual-carbon-goals-through-carbon-emissions-trading-market" tabindex="-1"><a class="header-anchor" href="#_30-why-achieve-dual-carbon-goals-through-carbon-emissions-trading-market" aria-hidden="true">#</a> 30. Why Achieve Dual Carbon Goals Through Carbon Emissions Trading Market?</h2><ol><li><strong>Definition of Carbon Emissions Trading Market</strong>: A mechanism that allows the buying and selling of carbon emission rights in the market, enabling companies to cope with carbon emission limits by purchasing or selling carbon quotas.</li><li><strong>Market Participants</strong>: Include central government, local governments, and emission-controlled enterprises, each responsible for carbon market policy-making, data verification, quota management, etc.</li><li><strong>Promoting Low-Carbon Transformation</strong>: The carbon market drives companies towards technological innovation and channels funds into low-carbon development by eliminating outdated capacities through incentive and constraint mechanisms.</li><li><strong>Total Emission Control Mechanism</strong>: Manages total carbon emissions by setting emission caps and quota trading, reducing emissions from the source.</li><li><strong>Promoting Internationalization of the RMB</strong>: Establishing a carbon emissions trading market helps to gain international carbon pricing rights and enhances China&#39;s influence in the international carbon market.</li><li><strong>Current Status of China&#39;s Carbon Market</strong>: China has established local pilot programs and a national carbon market, starting with the electricity industry and planning to expand to cover more sectors.</li><li><strong>Primarily Offline Trading</strong>: Currently, the carbon market mainly involves offline trading, with carbon financial products like carbon futures introduced in some pilot areas.</li><li><strong>Need for Stronger Policy Guarantees</strong>: Clear reward and punishment systems, unified carbon quota allocation standards, and the development of carbon financial derivatives are needed to enhance market efficiency.</li><li><strong>Strategic Adjustment by Enterprises</strong>: Enterprises need to adapt to the carbon market in advance, enhancing low-carbon development and carbon asset management capabilities through strategic adjustment and internal management.</li><li><strong>Reflections on Carbon Market Development</strong>: Current carbon emission trading prices have not effectively constrained fossil fuel use, and responsibilities across the entire industry value chain are not yet balanced. Consideration of broader industry coverage and policy adjustments is needed.</li></ol><h2 id="_31-what-is-the-green-finance-system-why-develop-a-green-finance-system" tabindex="-1"><a class="header-anchor" href="#_31-what-is-the-green-finance-system-why-develop-a-green-finance-system" aria-hidden="true">#</a> 31. What is the Green Finance System? Why Develop a Green Finance System?</h2><ol><li><strong>Support of Green Finance for Carbon Neutrality</strong>: Green finance supports the development of low-carbon industries and helps adjust and transform high-carbon industries through capital allocation, risk management, and market pricing, impacting macroeconomic output and efficiency.</li><li><strong>Green Finance and Negative Externalities</strong>: Compared to traditional finance, green finance considers the elimination of negative externalities in resource allocation, i.e., reducing environmental harm caused by enterprises to society.</li><li><strong>Central Bank Support for Green Finance</strong>: The People&#39;s Bank of China includes green credit and green bonds in the collateral scope of central bank lending facilities, creating tools to support carbon reduction and encouraging financial institutions to increase green investments.</li><li><strong>Leading Role of Green Credit</strong>: As the core of green finance, green credit supports environmental projects and low-carbon industries of enterprises, with room for growth in China&#39;s financial system.</li><li><strong>Implementation Issues of Green Credit</strong>: In promoting green credit, it&#39;s necessary to solve problems like judging the green attributes of projects and calculating environmental benefits to ensure efficient resource allocation.</li><li><strong>Role of Green Bonds</strong>: Although green bonds currently have a small share, they are expected to grow under carbon neutrality initiatives. They are securities that raise funds exclusively for green projects, including green financial bonds, corporate bonds, etc.</li><li><strong>Green Bond Issuance Process</strong>: Issuing green bonds requires project assessment based on the &quot;Green Bond Endorsed Project Catalogue&quot; to ensure funds are used for specified green industries and projects.</li><li><strong>Potential of Green Equity Investment</strong>: Green equity investment focuses on the non-standardized market, addressing the massive investment needs brought by carbon neutrality goals, involving clean energy, low-carbon manufacturing, and more.</li><li><strong>Investors&#39; Considerations for Green Projects</strong>: Investors consider the stability of returns and the refinancing ability of green projects, ensuring long-term investment returns.</li><li><strong>Challenges of Green Finance</strong>: Achieving carbon neutrality goals requires significant funding, but mismatches in funding supply and demand could pose problems for the financial system. Policymakers need to balance economic, social, and environmental benefits.</li><li><strong>Impact of Green Finance on the Economy</strong>: Green finance investments could reach several trillion yuan, offering huge opportunities for financial institutions and profoundly impacting industrial and employment structures.</li></ol><figure><img src="'+p+'" alt="Green Finance Industry Carbon Neutrality Relationship" tabindex="0" loading="lazy"><figcaption>Green Finance Industry Carbon Neutrality Relationship</figcaption></figure><h2 id="_33-what-can-individuals-do" tabindex="-1"><a class="header-anchor" href="#_33-what-can-individuals-do" aria-hidden="true">#</a> 33. What Can Individuals Do?</h2><ol><li><strong>Individual Responsibility and Obligations</strong>: Carbon neutrality is not just a national issue but also intimately related to every individual. People should actively participate and adopt energy-saving and emission-reducing habits as part of embracing the era of carbon neutrality.</li><li><strong>Low-Carbon Environmental Practices</strong>: Individuals can contribute to carbon neutrality by practicing green travel, eco-friendly office behavior, reducing energy consumption, decreasing meat intake, and tree planting, thus reducing personal carbon emissions.</li><li><strong>Research and Career Choices</strong>: Consider carbon neutrality-related technologies and specialties in professional and career choices, such as energy-saving technologies, or start businesses in low-carbon environmental protection fields to adapt to and promote the carbon neutrality process.</li></ol><h2 id="_34-what-can-enterprises-do" tabindex="-1"><a class="header-anchor" href="#_34-what-can-enterprises-do" aria-hidden="true">#</a> 34. What Can Enterprises Do?</h2>',39),v=i("<li><p><strong>Importance of Carbon Neutrality for Enterprises</strong>: Enterprises are key to achieving carbon neutrality and should actively participate in the low-carbon transformation and capitalize on the energy transition.</p></li><li><p><strong>Current Carbon Neutrality Status</strong>: Chinese enterprises have started to pay attention to carbon neutrality, but many lack spontaneous awareness of carbon reduction goals and need more specific actions.</p></li><li><p><strong>Definition of Carbon Emission Scope</strong>: Enterprises should clarify their carbon emission scope, referring to the &quot;Greenhouse Gas Accounting System&quot;.</p><blockquote><p>Carbon emission scopes can be referenced from the &quot;Greenhouse Gas Protocol&quot; established by the World Resources Institute (WRI) and the World Business Council for Sustainable Development (WBCSD), dividing enterprise carbon emissions into Scope 1, Scope 2, and Scope 3. Different types of enterprises have varying emissions in each scope.</p><p>Scope 1: refers to emissions from an enterprise&#39;s own facilities, e.g., raw material production and processing in manufacturing, fuel combustion in the energy industry;</p><p>Scope 2: covers emissions from energy purchased by the enterprise, e.g., emissions from purchased electricity and steam, represented by the internet tech industry—data centers&#39; purchased electricity;</p><p>Scope 3: includes all other emissions, such as purchased goods and services, upstream and downstream industry chains, and the use phase of sold products, e.g., employee business trips, upstream and downstream transportation and distribution, and leased assets.</p></blockquote></li>",3),w=e("p",null,[e("strong",null,"Carbon Accounting Methods"),n(": Enterprises should use international standards like ISO-14064 and ISO-14067 for carbon accounting, considering new technologies to improve accuracy.")],-1),C=e("p",null,"ISO-14064 enterprise carbon verification calculates the annual total carbon emissions of an enterprise, covering only Scope 1 and Scope 2 emissions, commonly used in enterprise carbon emission rights trading and carbon reduction verification.",-1),T=e("li",null,[e("p",null,"Greenhouse Gas (GHG) Emission Calculation:"),e("p",null,"GHG = Activity Data x GHG Emission Factor")],-1),k={class:"MathJax",jax:"SVG",style:{position:"relative"}},S={style:{"vertical-align":"-0.339ex"},xmlns:"http://www.w3.org/2000/svg",width:"4.433ex",height:"1.934ex",role:"img",focusable:"false",viewBox:"0 -705 1959.6 855","aria-hidden":"true"},_=i('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="mi"><path data-c="1D436" d="M50 252Q50 367 117 473T286 641T490 704Q580 704 633 653Q642 643 648 636T656 626L657 623Q660 623 684 649Q691 655 699 663T715 679T725 690L740 705H746Q760 705 760 698Q760 694 728 561Q692 422 692 421Q690 416 687 415T669 413H653Q647 419 647 422Q647 423 648 429T650 449T651 481Q651 552 619 605T510 659Q484 659 454 652T382 628T299 572T226 479Q194 422 175 346T156 222Q156 108 232 58Q280 24 350 24Q441 24 512 92T606 240Q610 253 612 255T628 257Q648 257 648 248Q648 243 647 239Q618 132 523 55T319 -22Q206 -22 128 53T50 252Z"></path></g><g data-mml-node="msub" transform="translate(760,0)"><g data-mml-node="mi"><path data-c="1D442" d="M740 435Q740 320 676 213T511 42T304 -22Q207 -22 138 35T51 201Q50 209 50 244Q50 346 98 438T227 601Q351 704 476 704Q514 704 524 703Q621 689 680 617T740 435ZM637 476Q637 565 591 615T476 665Q396 665 322 605Q242 542 200 428T157 216Q157 126 200 73T314 19Q404 19 485 98T608 313Q637 408 637 476Z"></path></g><g data-mml-node="mn" transform="translate(796,-150) scale(0.707)"><path data-c="32" d="M109 429Q82 429 66 447T50 491Q50 562 103 614T235 666Q326 666 387 610T449 465Q449 422 429 383T381 315T301 241Q265 210 201 149L142 93L218 92Q375 92 385 97Q392 99 409 186V189H449V186Q448 183 436 95T421 3V0H50V19V31Q50 38 56 46T86 81Q115 113 136 137Q145 147 170 174T204 211T233 244T261 278T284 308T305 340T320 369T333 401T340 431T343 464Q343 527 309 573T212 619Q179 619 154 602T119 569T109 550Q109 549 114 549Q132 549 151 535T170 489Q170 464 154 447T109 429Z"></path></g></g></g></g>',1),I=[_],Q=e("mjx-assistive-mml",{unselectable:"on",display:"inline"},[e("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[e("mi",null,"C"),e("msub",null,[e("mi",null,"O"),e("mn",null,"2")])])],-1),E={class:"MathJax",jax:"SVG",style:{position:"relative"}},x={style:{"vertical-align":"-0.339ex"},xmlns:"http://www.w3.org/2000/svg",width:"4.433ex",height:"1.934ex",role:"img",focusable:"false",viewBox:"0 -705 1959.6 855","aria-hidden":"true"},G=i('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="mi"><path data-c="1D436" d="M50 252Q50 367 117 473T286 641T490 704Q580 704 633 653Q642 643 648 636T656 626L657 623Q660 623 684 649Q691 655 699 663T715 679T725 690L740 705H746Q760 705 760 698Q760 694 728 561Q692 422 692 421Q690 416 687 415T669 413H653Q647 419 647 422Q647 423 648 429T650 449T651 481Q651 552 619 605T510 659Q484 659 454 652T382 628T299 572T226 479Q194 422 175 346T156 222Q156 108 232 58Q280 24 350 24Q441 24 512 92T606 240Q610 253 612 255T628 257Q648 257 648 248Q648 243 647 239Q618 132 523 55T319 -22Q206 -22 128 53T50 252Z"></path></g><g data-mml-node="msub" transform="translate(760,0)"><g data-mml-node="mi"><path data-c="1D442" d="M740 435Q740 320 676 213T511 42T304 -22Q207 -22 138 35T51 201Q50 209 50 244Q50 346 98 438T227 601Q351 704 476 704Q514 704 524 703Q621 689 680 617T740 435ZM637 476Q637 565 591 615T476 665Q396 665 322 605Q242 542 200 428T157 216Q157 126 200 73T314 19Q404 19 485 98T608 313Q637 408 637 476Z"></path></g><g data-mml-node="mn" transform="translate(796,-150) scale(0.707)"><path data-c="32" d="M109 429Q82 429 66 447T50 491Q50 562 103 614T235 666Q326 666 387 610T449 465Q449 422 429 383T381 315T301 241Q265 210 201 149L142 93L218 92Q375 92 385 97Q392 99 409 186V189H449V186Q448 183 436 95T421 3V0H50V19V31Q50 38 56 46T86 81Q115 113 136 137Q145 147 170 174T204 211T233 244T261 278T284 308T305 340T320 369T333 401T340 431T343 464Q343 527 309 573T212 619Q179 619 154 602T119 569T109 550Q109 549 114 549Q132 549 151 535T170 489Q170 464 154 447T109 429Z"></path></g></g></g></g>',1),P=[G],A=e("mjx-assistive-mml",{unselectable:"on",display:"inline"},[e("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[e("mi",null,"C"),e("msub",null,[e("mi",null,"O"),e("mn",null,"2")])])],-1),q=e("p",null,"The second method is based on ISO 14067 standards, accounting for emissions from Scope 1, Scope 2, and Scope 3. This method involves emissions throughout the supply chain and is more challenging to accurately account for. However, most enterprises do not perform large amounts of direct carbon emissions as per the first method, making it difficult to meet the thresholds of carbon emission rights trading markets and limiting the potential for emission reductions.",-1),z=i("<li><p><strong>Setting Scientific Carbon Reduction Targets</strong>: Enterprises should set scientific carbon reduction targets based on their characteristics and national goals, referring to the guidelines of the Science Based Target Initiative (SBTI).</p><blockquote><p>SBTI requires that when setting scientific carbon targets, enterprises should cover at least 95% of their Scope 1 and Scope 2 emissions, encouraging enterprises to set carbon targets based on scenarios where the global average temperature increase is controlled within 1.5℃. For Scope 3 targets, when an enterprise&#39;s Scope 3 emissions exceed 40% of its total emissions, it needs to set Scope 3 reduction targets covering at least 2/3 of its total Scope 3 emissions, with certain specific industries required to set Scope 3 targets. When implementing SBTI, it is important to note that &quot;carbon offset&quot; and &quot;avoided emissions&quot; do not count towards scientific carbon targets, encouraging enterprises to implement active emission reduction measures to reduce absolute emissions.</p></blockquote></li><li><p><strong>Development of an Action Roadmap</strong>: Clarify emission reduction implementation paths, including energy substitution and efficiency improvement, tailored to the specific characteristics of the enterprise.</p></li><li><p><strong>Focus on &#39;Core Emission Reduction&#39;</strong>: Enterprises should deeply adjust their energy and industrial structures, develop low-carbon technologies, and reduce overreliance on carbon compensation.</p></li><li><p><strong>Whole Supply Chain Management</strong>: Establish a whole supply chain carbon neutrality management system, including low-carbon requirements and assessments for suppliers.</p></li><li><p><strong>Empowerment through Digital Transformation</strong>: Enterprises should use digital technologies to empower low-carbon transformation and accelerate the achievement of carbon neutrality goals.</p></li><li><p><strong>Addressing Carbon Tariff Impact</strong>: Enterprises should assess the costs of carbon reduction and adapt to international carbon tariff policies, incorporating carbon costs into business decisions.</p></li>",6),D=i('<h2 id="_35-what-can-financial-institutions-do" tabindex="-1"><a class="header-anchor" href="#_35-what-can-financial-institutions-do" aria-hidden="true">#</a> 35. What Can Financial Institutions Do?</h2><ol><li><strong>Innovate Green Financial Products</strong>: Financial institutions should continuously improve the green financial product system, providing customized financial tools and services to support the green and low-carbon development needs of businesses.</li><li><strong>Enhance Carbon Financial Risk Management</strong>: Financial institutions need to optimize risk assessment and early warning mechanisms, utilize financial technology to improve risk control capabilities, and strengthen pre-investment investigations and post-investment risk management in ESG investments.</li><li><strong>Engage in International Cooperation on Green Finance</strong>: Promote the development of green low-carbon technologies and green investments by establishing international green funds and strengthening cooperation with countries along the &quot;Belt and Road&quot; initiative, enhancing the role in the global carbon market.</li></ol><h2 id="_36-what-can-governments-do" tabindex="-1"><a class="header-anchor" href="#_36-what-can-governments-do" aria-hidden="true">#</a> 36. What Can Governments Do?</h2><ol><li><strong>System Building and Action Planning</strong>: Governments should formulate macro action paths for carbon neutrality, encourage localities to design their own carbon neutrality routes, and clarify carbon emission targets for various industries and regions.</li><li><strong>Environmental Protection Legislation and Technology Industry Planning</strong>: Accelerate the formulation of laws to address climate change, ensure the protection of carbon neutrality goals, support the development of zero-carbon technologies, and strengthen intellectual property rights protection.</li><li><strong>Carbon Emissions Trading System and Green Financial Market Development</strong>: Improve the carbon emissions trading system, clarify reward and punishment mechanisms, and hasten the perfection of the green finance policy framework to guide financial institutions in supporting green projects.</li><li><strong>International Cooperation and Participation in Technical Standards</strong>: Actively participate in international carbon neutrality technology cooperation, draw on advanced experiences, and participate in formulating international technical and industry low-carbon standards to ensure the efficiency and fairness of international cooperation.</li><li><strong>Participation in the Development of International Technical Standards</strong>: Governments should actively participate in the formulation of international technical standards and industry low-carbon standards to increase international influence and guide the development of international industry low-carbon standards.</li></ol>',4);function M(N,R){const a=s("RouterLink");return t(),o("div",null,[y,e("p",null,[n("First part: "),l(a,{to:"/notes/climate/20231213.CarbonNeutralityNote1.html"},{default:c(()=>[n("Understanding Carbon Neutrality: Notes Part 1")]),_:1})]),b,e("ol",null,[v,e("li",null,[w,e("blockquote",null,[C,e("ol",null,[T,e("li",null,[e("p",null,[n("Conversion of GHG into Carbon Dioxide Equivalent ("),e("mjx-container",k,[(t(),o("svg",S,I)),Q]),n("e) using Global Warming Potential (GWP):")]),e("p",null,[e("mjx-container",E,[(t(),o("svg",x,P)),A]),n("e = GHG x GWP")])])]),q])]),z]),D])}const B=r(f,[["render",M],["__file","20231214.CarbonNeutralityNote2.html.vue"]]);export{B as default};
